cat <<'EOF' > csv-parser.ts
export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export type CSVRow = Record<string, any>;

export interface CSVResult {
  rows: CSVRow[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: CSVRow) => boolean): CSVRow[];
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<any, CSVRow[]>;
}

type RowField = {
  value: string;
  quoted: boolean;
};

type RawRow = {
  fields: RowField[];
  rowNumber: number;
};

const coerceField = (value: string, quoted: boolean): any => {
  const trimmed = value.trim();
  if (trimmed === '') {
    return null;
  }

  const normalized = trimmed.toLowerCase();
  if (normalized === 'null') {
    return null;
  }

  if (normalized === 'true') {
    return true;
  }

  if (normalized === 'false') {
    return false;
  }

  if (/^-?\d+(\.\d+)?$/.test(trimmed)) {
    return Number(trimmed);
  }

  return quoted ? value : trimmed;
};

const buildResult = (
  headers: string[],
  rows: CSVRow[],
  errors: CSVError[]
): CSVResult => {
  const filter = (predicate: (row: CSVRow) => boolean): CSVRow[] => rows.filter(predicate);

  const sum = (column: string): number => {
    let total = 0;
    for (const row of rows) {
      const value = row[column];
      if (typeof value === 'number' && !Number.isNaN(value)) {
        total += value;
      }
    }
    return total;
  };

  const average = (column: string): number => {
    let total = 0;
    let count = 0;
    for (const row of rows) {
      const value = row[column];
      if (typeof value === 'number' && !Number.isNaN(value)) {
        total += value;
        count += 1;
      }
    }
    return count === 0 ? 0 : total / count;
  };

  const count = (): number => rows.length;

  const groupBy = (column: string): Map<any, CSVRow[]> => {
    const groups = new Map<any, CSVRow[]>();
    for (const row of rows) {
      const key = row[column];
      const existing = groups.get(key);
      if (existing) {
        existing.push(row);
      } else {
        groups.set(key, [row]);
      }
    }
    return groups;
  };

  return {
    rows,
    headers,
    errors,
    filter,
    sum,
    average,
    count,
    groupBy,
  };
};

export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter && options.delimiter.length > 0 ? options.delimiter : ',';
  const quote = options.quote && options.quote.length > 0 ? options.quote : '"';
  const providedLineSeparator = options.lineSeparator && options.lineSeparator.length > 0 ? options.lineSeparator : undefined;

  let normalizedInput = input ?? '';
  if (!providedLineSeparator) {
    normalizedInput = normalizedInput.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
  }

  const lineSeparator = providedLineSeparator ?? '\n';
  const delimiterLen = delimiter.length;
  const lineSepLen = lineSeparator.length;

  const errors: CSVError[] = [];
  const rows: RawRow[] = [];
  let currentRowNumber = 1;
  let insideQuotes = false;
  let currentField = '';
  let currentFieldQuoted = false;
  let rowFields: RowField[] = [];

  const addField = () => {
    rowFields.push({ value: currentField, quoted: currentFieldQuoted });
    currentField = '';
    currentFieldQuoted = false;
  };

  const pushRow = () => {
    rows.push({ fields: rowFields.slice(), rowNumber: currentRowNumber });
    rowFields = [];
    currentRowNumber += 1;
  };

  for (let i = 0; i < normalizedInput.length; i += 1) {
    const char = normalizedInput[i];

    if (insideQuotes) {
      if (char === quote) {
        const next = normalizedInput[i + 1];
        if (next === quote) {
          currentField += quote;
          i += 1;
          continue;
        }
        insideQuotes = false;
        continue;
      }
      currentField += char;
      continue;
    }

    if (char === quote) {
      insideQuotes = true;
      currentFieldQuoted = true;
      continue;
    }

    if (delimiterLen > 0 && normalizedInput.startsWith(delimiter, i)) {
      addField();
      i += delimiterLen - 1;
      continue;
    }

    if (lineSepLen > 0 && normalizedInput.startsWith(lineSeparator, i)) {
      addField();
      pushRow();
      i += lineSepLen - 1;
      continue;
    }

    currentField += char;
  }

  if (insideQuotes) {
    errors.push({ row: currentRowNumber, message: 'Unterminated quoted field' });
    insideQuotes = false;
  }

  if (currentField.length > 0 || currentFieldQuoted || rowFields.length > 0) {
    addField();
    pushRow();
  }

  if (rows.length === 0) {
    return buildResult([], [], errors);
  }

  const headerRow = rows[0];
  const headers = headerRow.fields.map((field) => field.value);
  const dataRows = rows.slice(1);
  const csvRows: CSVRow[] = [];

  for (const row of dataRows) {
    if (row.fields.length !== headers.length) {
      errors.push({
        row: row.rowNumber,
        message: `Expected ${headers.length} fields but got ${row.fields.length}`,
      });
    }

    const entry: CSVRow = {};
    for (let idx = 0; idx < headers.length; idx += 1) {
      const field = row.fields[idx];
      entry[headers[idx]] = field ? coerceField(field.value, field.quoted) : null;
    }
    csvRows.push(entry);
  }

  return buildResult(headers, csvRows, errors);
}
