cat <<'EOF' > csv-parser.test.ts
import { parseCSV } from './csv-parser';

const assert = (condition: boolean, message: string) => {
  if (!condition) {
    throw new Error(message);
  }
};

const assertEqual = (actual: any, expected: any, label: string) => {
  if (actual !== expected) {
    throw new Error(`${label}: expected ${expected}, got ${actual}`);
  }
};

// Basic parsing
(() => {
  const input = 'name,age\nAlice,30\nBob,25';
  const result = parseCSV(input);
  assertEqual(result.headers.length, 2, 'Basic headers count');
  assertEqual(result.rows.length, 2, 'Basic rows count');
  assertEqual(result.rows[0].name, 'Alice', 'Basic first row value');
  assertEqual(result.rows[1].age, 25, 'Basic numeric coercion');
})();

// Quoted fields containing commas
(() => {
  const input = 'name,address\n"John Doe","123, Main St"\n"Jane Doe","456, Oak Ave"';
  const result = parseCSV(input);
  assertEqual(result.rows[0].address, '123, Main St', 'Quoted comma included');
  assertEqual(result.rows[1].name, 'Jane Doe', 'Quoted name preserved');
})();

// Escaped quotes inside quoted fields
(() => {
  const input = 'id,quote\n1,"He said ""Hello"""';
  const result = parseCSV(input);
  assertEqual(result.rows[0].quote, 'He said "Hello"', 'Escaped quote handled');
})();

// Custom delimiters and quote characters
(() => {
  const input = 'name|age\nAlice|30\nBob|25';
  const result = parseCSV(input, { delimiter: '|' });
  assertEqual(result.rows[0].age, 30, 'Custom delimiter parsing');
})();

// Type coercion for numbers, booleans, nulls, and strings
(() => {
  const input = [
    'intVal,floatVal,boolVal,bool2,nullVal,emptyVal,stringVal,spacedVal',
    '1,42,true,false,NULL,"","plain","  quoted  "',
    '2,3.14,false,true,null,,value2,  trimmed  ',
  ].join('\n');
  const result = parseCSV(input);
  const [first, second] = result.rows;

  assertEqual(first.intVal, 1, 'Number conversion (int)');
  assertEqual(first.floatVal, 42, 'Number conversion (float as integer)');
  assertEqual(first.boolVal, true, 'Boolean true conversion');
  assertEqual(first.bool2, false, 'Boolean false conversion');
  assertEqual(first.nullVal, null, 'Null conversion (NULL)');
  assertEqual(first.emptyVal, null, 'Empty quoted string to null');
  assertEqual(first.stringVal, 'plain', 'Unquoted strings preserved');
  assertEqual(first.spacedVal, '  quoted  ', 'Quoted strings preserve spaces');

  assertEqual(second.intVal, 2, 'Second row int conversion');
  assertEqual(second.floatVal, 3.14, 'Second row float conversion');
  assertEqual(second.boolVal, false, 'Second row boolean false');
  assertEqual(second.bool2, true, 'Second row boolean true');
  assertEqual(second.nullVal, null, 'Second row null value');
  assertEqual(second.emptyVal, null, 'Second row empty field becomes null');
  assertEqual(second.stringVal, 'value2', 'Second row string value');
  assertEqual(second.spacedVal, 'trimmed', 'Unquoted spaced string trims');
})();

// Malformed row error collection
(() => {
  const input = 'name,age\nAlice,30\nBob\nCharlie,25,extra';
  const result = parseCSV(input);
  assertEqual(result.errors.length, 2, 'Malformed row count');
  assert(result.errors.some((err) => err.row === 3), 'Missing field error captured');
  assert(result.errors.some((err) => err.row === 4), 'Extra field error captured');
})();

// Filter functionality
(() => {
  const input = 'name,age\nAlice,30\nBob,22\nCharlie,35';
  const result = parseCSV(input);
  const filtered = result.filter((row) => row.age >= 30);
  assertEqual(filtered.length, 2, 'Filter selects correct rows');
  assert(filtered.every((row) => row.age >= 30), 'Filter predicate respected');
  assert(filtered !== result.rows, 'Filter returns new array');
})();

// Aggregation methods
(() => {
  const input = 'group,value\nA,10\nB,20\nA,5\nC,not a number\nB,15';
  const result = parseCSV(input);
  assertEqual(result.sum('value'), 50, 'Sum only numeric values');
  assertEqual(result.average('value'), 12.5, 'Average calculation');
  assertEqual(result.count(), 5, 'Count includes all rows');
  const grouped = result.groupBy('group');
  assertEqual(grouped.get('A')?.length, 2, 'Group A has two rows');
  assertEqual(grouped.get('B')?.length, 2, 'Group B has two rows');
  assertEqual(grouped.get('C')?.length, 1, 'Group C has one row');
})();

// Edge cases: empty input, single column/row, large fields
(() => {
  const empty = parseCSV('');
  assertEqual(empty.rows.length, 0, 'Empty input yields no rows');
  assertEqual(empty.headers.length, 0, 'Empty input yields no headers');
  assertEqual(empty.count(), 0, 'Count handles no rows');

  const singleColumn = parseCSV('value\nonly');
  assertEqual(singleColumn.headers[0], 'value', 'Header detected for single column');
  assertEqual(singleColumn.rows[0].value, 'only', 'Single column value parsed');

  const singleRow = parseCSV('a,b\n1,2');
  assertEqual(singleRow.count(), 1, 'Single data row counted');

  const largeText = 'text\n"' + 'x'.repeat(10000) + '"';
  const large = parseCSV(largeText);
  assertEqual(large.rows[0].text.length, 10000, 'Large text field retained');
})();

console.log('All csv-parser tests passed');
EOF

